query:
DELETE FROM messages WHERE id IN (
  SELECT id FROM (
    SELECT m2.id
    FROM messages m1
    JOIN messages m2 ON m1.messageId = m2.messageId AND m1.sessionId = m2.sessionId AND m1.id < m2.id
    WHERE m1.messageId IS NOT NULL
    LIMIT 5000
  ) tmp
);

